import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import './Dashboard.css';

function Dashboard() {
    const [chatbots, setChatbots] = useState([]);
    const [showForm, setShowForm] = useState(false);
    const [currentBot, setCurrentBot] = useState({
        id: '',
        name: '',
        chatLogoColor: '#3884db',
        chatLogoImage: '',
        iconAvatarImage: '',
        staticImage: '',
        chatHeaderColor: '#b4c7c5',
        chatBackgroundColor: '#e9f0f7',
        bodyBackgroundImage: '',
        welcomeText: 'Welcome to our assistant! How can I help you today?',
        apiKey: ''
    });

    useEffect(() => {
        // Load saved chatbots from localStorage
        const savedChatbots = localStorage.getItem('chatbots');
        if (savedChatbots) {
            setChatbots(JSON.parse(savedChatbots));
        }
    }, []);

    // Save chatbots to localStorage whenever they change
    useEffect(() => {
        localStorage.setItem('chatbots', JSON.stringify(chatbots));
    }, [chatbots]);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setCurrentBot({
            ...currentBot,
            [name]: value
        });
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        const newBot = {
            ...currentBot,
            id: currentBot.id || Date.now().toString() // Use existing ID or create new one
        };

        if (currentBot.id) {
            // Update existing bot
            setChatbots(chatbots.map(bot => bot.id === currentBot.id ? newBot : bot));
        } else {
            // Add new bot
            setChatbots([...chatbots, newBot]);
        }

        // Reset form
        setCurrentBot({
            id: '',
            name: '',
            chatLogoColor: '#3884db',
            chatLogoImage: '',
            iconAvatarImage: '',
            staticImage: '',
            chatHeaderColor: '#b4c7c5',
            chatBackgroundColor: '#e9f0f7',
            bodyBackgroundImage: '',
            welcomeText: 'Welcome to our assistant! How can I help you today?',
            apiKey: ''
        });

        setShowForm(false);
    };

    const editChatbot = (bot) => {
        setCurrentBot(bot);
        setShowForm(true);
    };

    const deleteChatbot = (id) => {
        setChatbots(chatbots.filter(bot => bot.id !== id));
    };

    const launchChatbot = (bot) => {
        // Store the selected bot in sessionStorage
        sessionStorage.setItem('selectedChatbot', JSON.stringify(bot));

        // Open in a new tab
        window.open('/chatbot', '_blank');
    };

    return (
        <div className="dashboard-container">
            <header className="dashboard-header">
                <h1>Chatbot Management Dashboard</h1>
                <button 
                    className="create-button"
                    onClick={() => setShowForm(true)}
                >
                    Create New Chatbot
                </button>
            </header>

            {showForm && (
                <div className="form-overlay">
                    <div className="form-container">
                        <h2>{currentBot.id ? 'Edit Chatbot' : 'Create New Chatbot'}</h2>
                        <form onSubmit={handleSubmit}>
                            <div className="form-grid">
                                <div className="form-group">
                                    <label>Name</label>
                                    <input 
                                        type="text" 
                                        name="name" 
                                        value={currentBot.name} 
                                        onChange={handleInputChange}
                                        required
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Chat Logo Color</label>
                                    <div className="color-input">
                                        <input 
                                            type="color" 
                                            name="chatLogoColor" 
                                            value={currentBot.chatLogoColor} 
                                            onChange={handleInputChange}
                                        />
                                        <input 
                                            type="text" 
                                            name="chatLogoColor" 
                                            value={currentBot.chatLogoColor} 
                                            onChange={handleInputChange}
                                        />
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label>Chat Logo Image (URL)</label>
                                    <input 
                                        type="text" 
                                        name="chatLogoImage" 
                                        value={currentBot.chatLogoImage} 
                                        onChange={handleInputChange}
                                        placeholder="URL or path to image in public folder"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Icon Avatar Image (URL)</label>
                                    <input 
                                        type="text" 
                                        name="iconAvatarImage" 
                                        value={currentBot.iconAvatarImage} 
                                        onChange={handleInputChange}
                                        placeholder="URL or path to image in public folder"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Static Image (URL)</label>
                                    <input 
                                        type="text" 
                                        name="staticImage" 
                                        value={currentBot.staticImage} 
                                        onChange={handleInputChange}
                                        placeholder="URL or path to image in public folder"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Chat Header Color</label>
                                    <div className="color-input">
                                        <input 
                                            type="color" 
                                            name="chatHeaderColor" 
                                            value={currentBot.chatHeaderColor} 
                                            onChange={handleInputChange}
                                        />
                                        <input 
                                            type="text" 
                                            name="chatHeaderColor" 
                                            value={currentBot.chatHeaderColor} 
                                            onChange={handleInputChange}
                                        />
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label>Chat Background Color</label>
                                    <div className="color-input">
                                        <input 
                                            type="color" 
                                            name="chatBackgroundColor" 
                                            value={currentBot.chatBackgroundColor} 
                                            onChange={handleInputChange}
                                        />
                                        <input 
                                            type="text" 
                                            name="chatBackgroundColor" 
                                            value={currentBot.chatBackgroundColor} 
                                            onChange={handleInputChange}
                                        />
                                    </div>
                                </div>

                                <div className="form-group">
                                    <label>Body Background Image (URL)</label>
                                    <input 
                                        type="text" 
                                        name="bodyBackgroundImage" 
                                        value={currentBot.bodyBackgroundImage} 
                                        onChange={handleInputChange}
                                        placeholder="URL or path to image in public folder"
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Welcome Text</label>
                                    <textarea 
                                        name="welcomeText" 
                                        value={currentBot.welcomeText} 
                                        onChange={handleInputChange}
                                        required
                                    ></textarea>
                                </div>

                                <div className="form-group">
                                    <label>NEXT_AGI_API_KEY</label>
                                    <input 
                                        type="text" 
                                        name="apiKey" 
                                        value={currentBot.apiKey} 
                                        onChange={handleInputChange}
                                        required
                                    />
                                </div>
                            </div>

                            <div className="form-actions">
                                <button type="submit" className="save-button">
                                    {currentBot.id ? 'Update Chatbot' : 'Create Chatbot'}
                                </button>
                                <button 
                                    type="button" 
                                    className="cancel-button"
                                    onClick={() => {
                                        setShowForm(false);
                                        setCurrentBot({
                                            id: '',
                                            name: '',
                                            chatLogoColor: '#3884db',
                                            chatLogoImage: '',
                                            iconAvatarImage: '',
                                            staticImage: '',
                                            chatHeaderColor: '#b4c7c5',
                                            chatBackgroundColor: '#e9f0f7',
                                            bodyBackgroundImage: '',
                                            welcomeText: 'Welcome to our assistant! How can I help you today?',
                                            apiKey: ''
                                        });
                                    }}
                                >
                                    Cancel
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            <div className="chatbots-grid">
                {chatbots.map(bot => (
                    <div key={bot.id} className="chatbot-card">
                        <div 
                            className="chatbot-logo" 
                            style={{backgroundColor: bot.chatLogoColor}}
                            onClick={() => launchChatbot(bot)}
                        >
                            {bot.chatLogoImage ? (
                                <img src={bot.chatLogoImage} alt={bot.name} />
                            ) : (
                                <div className="default-logo">{bot.name.charAt(0)}</div>
                            )}
                        </div>
                        <h3>{bot.name}</h3>
                        <div className="card-actions">
                            <button onClick={() => editChatbot(bot)}>Edit</button>
                            <button onClick={() => deleteChatbot(bot.id)}>Delete</button>
                            <button onClick={() => launchChatbot(bot)}>Launch</button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

export default Dashboard;
